<script>
// notif toggle
function toggleNotif\(\){
  document.getElementById\('notifDrop'\).classList.toggle\('show'\);
}
document.addEventListener\('click', e => {
  if\(!e.target.closest\('.notif-wrap'\)\) document.getElementById\('notifDrop'\).classList.remove\('show'\);
}\);

// === RADAR ===
const canvas = document.getElementById\('radar'\);
const ctx = canvas.getContext\('2d'\);
const W=canvas.width, H=canvas.height, cx=W/2, cy=H/2+5, maxR=Math.min\(W,H\)*.37;
const labels=['Analytical\\nThinking','Language &\\nExpression','Creative\\nThinking','Physical\\nEngagement','Academic\\nConsistency','Emotional\\nWellbeing'];
const student=[0.82,0.70,0.88,0.65,0.78,0.58];
const avg=[0.65,0.68,0.72,0.70,0.66,0.72];
const N=labels.length, step=\(Math.PI*2\)/N, start=-Math.PI/2;
const px=\(r,i\)=>cx+r*Math.cos\(start+i*step\);
const py=\(r,i\)=>cy+r*Math.sin\(start+i*step\);

function draw\(\){
  ctx.clearRect\(0,0,W,H\);
  // rings
  for\(let r=1;r<=5;r++\){
    ctx.beginPath\(\);
    const fr=\(maxR/5\)*r;
    for\(let i=0;i<N;i++\){i===0?ctx.moveTo\(px\(fr,i\),py\(fr,i\)\):ctx.lineTo\(px\(fr,i\),py\(fr,i\)\);}
    ctx.closePath\(\);
    ctx.strokeStyle=r===5?'rgba\(79,110,247,0.18\)':'rgba\(58,63,92,0.7\)';
    ctx.lineWidth=r===5?1.5:1;
    ctx.stroke\(\);
    // ring label
    if\(r===5||r===3\){
      ctx.fillStyle='rgba\(123,130,168,0.6\)';
      ctx.font='500 9px Inter,sans-serif';
      ctx.fillText\(\(r*20\)+'%',cx+4,cy-fr+2\);
    }
  }
  // axes
  for\(let i=0;i<N;i++\){ctx.beginPath\(\);ctx.moveTo\(cx,cy\);ctx.lineTo\(px\(maxR,i\),py\(maxR,i\)\);ctx.strokeStyle='rgba\(58,63,92,0.8\)';ctx.lineWidth=1;ctx.stroke\(\);}
  // avg
  ctx.beginPath\(\);
  for\(let i=0;i<N;i++\){const r=avg[i]*maxR;i===0?ctx.moveTo\(px\(r,i\),py\(r,i\)\):ctx.lineTo\(px\(r,i\),py\(r,i\)\);}
  ctx.closePath\(\);ctx.fillStyle='rgba\(58,63,92,0.5\)';ctx.strokeStyle='rgba\(90,96,140,0.6\)';ctx.lineWidth=1.5;ctx.fill\(\);ctx.stroke\(\);
  // student gradient
  const grad=ctx.createRadialGradient\(cx,cy,0,cx,cy,maxR\);
  grad.addColorStop\(0,'rgba\(99,102,241,0.6\)'\);grad.addColorStop\(1,'rgba\(139,92,246,0.15\)'\);
